using namespace std;

long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    vector<long long> S(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        S[i] = S[i - 1] + nums[i - 1];
    }
    vector<long long> dp(n + 1, 0);
    vector<long long> max_remainder(k, LLONG_MIN);
    max_remainder[0] = 0;
    for (int i = 1; i <= n; ++i) {
        long long current_S = S[i];
        long long r = current_S % k;
        long long candidate = LLONG_MIN;
        if (max_remainder[r] != LLONG_MIN) {
            candidate = max_remainder[r] + current_S;
        }
        dp[i] = max(dp[i - 1], candidate);
        long long current_val = dp[i] - current_S;
        if (current_val > max_remainder[r]) {
            max_remainder[r] = current_val;
        }
    }
    long long total_sum = S[n];
    return total_sum - dp[n];
}
